final:
module top_module (
    input r,
    input q,
    input z,
    input t,
    output reg valid_flag
);
    always @(*) begin
        case ({r, q, z, t})
            4'b0100: valid_flag = 1'b1;
            4'b1111: valid_flag = 1'b1;
            4'b0001: valid_flag = 1'b1;
            4'b1010: valid_flag = 1'b1;
            4'b0011: valid_flag = 1'b0;
            4'b0000: valid_flag = 1'b0;
            4'b1000: valid_flag = 1'b0;
            4'b1100: valid_flag = 1'b1;
            4'b0111: valid_flag = 1'b1;
            4'b1101: valid_flag = 1'b0;
            4'b0110: valid_flag = 1'b0;
            4'b1001: valid_flag = 1'b0;
            4'b0010: valid_flag = 1'b0;
            4'b0101: valid_flag = 1'b0;
            4'b1110: valid_flag = 1'b0;
            4'b1011: valid_flag = 1'b0;
        endcase
    end
endmodule
